1	import { useState } from "react";
2	import { View, Text, Textarea } from "@tarojs/components";
3	import { apiFetch } from "../../lib";
4	import "./index.scss";
5	
6	export default function InsightsPage() {
7	  const [insights, setInsights] = useState("");
8	  const [loading, setLoading] = useState(false);
9	  const [habitPrompt, setHabitPrompt] = useState("");
10	  const [generated, setGenerated] = useState("");
11	
12	  async function getWeeklyInsight() {
13	    setLoading(true);
14	    const data = await apiFetch("/api/insights", {
15	      method: "POST",
16	      body: JSON.stringify({ type: "weekly" }),
17	    });
18	    setInsights(data.text || "");
19	    setLoading(false);
20	  }
21	
22	  async function generateHabits() {
23	    if (!habitPrompt.trim()) return;
24	    setLoading(true);
25	    const data = await apiFetch("/api/insights", {
26	      method: "POST",
27	      body: JSON.stringify({ type: "generate-habits", prompt: habitPrompt }),
28	    });
29	    setGenerated(data.text || "");
30	    setLoading(false);
31	  }
32	
33	  return (
34	    <View className="page">
35	      <Text className="page-title">AI 洞察</Text>
36	      <Text className="page-subtitle">发现规律，精准提升</Text>
37	
38	      <View className="card">
39	        <Text className="card-title">✨ 本周洞察</Text>
40	        {insights ? (
41	          <Text className="insight-text">{insights}</Text>
42	        ) : (
43	          <Text className="card-desc">根据你的打卡数据生成个性化一周分析报告</Text>
44	        )}
45	        <Text className="action-btn" onClick={getWeeklyInsight}>
46	          {loading ? "生成中..." : "生成本周洞察"}
47	        </Text>
48	      </View>
49	
50	      <View className="card">
51	        <Text className="card-title">🎯 习惯生成器</Text>
52	        <Text className="card-desc">描述你的目标，AI 帮你拆解为可执行的习惯</Text>
53	        <Textarea
54	          className="textarea"
55	          placeholder="例如：我想提升商业分析能力，每天只有1小时空闲时间..."
56	          value={habitPrompt}
57	          onInput={(e) => setHabitPrompt(e.detail.value)}
58	        />
59	        <Text className="action-btn" onClick={generateHabits}>
60	          {loading ? "生成中..." : "生成习惯方案"}
61	        </Text>
62	        {generated ? (
63	          <Text className="insight-text" style={{ marginTop: "20rpx" }}>{generated}</Text>
64	        ) : null}
65	      </View>
66	    </View>
67	  );
68	}
